#define TGFLMC_BASE (ZOPFLI_CACHE_LENGTH * TGFLMC_LMCPOS * 3)
#define TGFLMC_MAXCACHED \
    ((s->lmc->sublen[TGFLMC_BASE + 1] == 0 && s->lmc->sublen[TGFLMC_BASE + 2] == 0) \
